package ru.memearena.vote.domain; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID; @Entity @Table(name="vote", uniqueConstraints=@UniqueConstraint(name="uk_vote_user_pair",columnNames={"user_id","pair_key"})) public class Vote { @Id private UUID id; @Column(name="user_id") private UUID userId; @Column(name="left_meme_id") private UUID leftMemeId; @Column(name="right_meme_id") private UUID rightMemeId; @Column(name="winner_meme_id") private UUID winnerMemeId; @Column(name="loser_meme_id") private UUID loserMemeId; @Column(name="pair_key") private String pairKey; @Column(name="winner_rating_before") private int winnerRatingBefore; @Column(name="winner_rating_after") private int winnerRatingAfter; @Column(name="loser_rating_before") private int loserRatingBefore; @Column(name="loser_rating_after") private int loserRatingAfter; @Column(name="created_at") private Instant createdAt; protected Vote(){} public Vote(UUID id,UUID userId,UUID left,UUID right,UUID winner,UUID loser,String pairKey,int wrb,int wra,int lrb,int lra,Instant now){this.id=id;this.userId=userId;this.leftMemeId=left;this.rightMemeId=right;this.winnerMemeId=winner;this.loserMemeId=loser;this.pairKey=pairKey;this.winnerRatingBefore=wrb;this.winnerRatingAfter=wra;this.loserRatingBefore=lrb;this.loserRatingAfter=lra;this.createdAt=now;} public UUID getId(){return id;} public UUID getUserId(){return userId;} public UUID getWinnerMemeId(){return winnerMemeId;} public UUID getLoserMemeId(){return loserMemeId;} public Instant getCreatedAt(){return createdAt;} public static String pairKey(UUID a,UUID b){return a.toString().compareTo(b.toString())<0?a+":"+b:b+":"+a;} }
